SELECT notification_id, to_user_id, biz_type, target_type, target_id, post_id, root_comment_id, last_actor_user_id, last_comment_id, unread_count, create_time, update_time FROM interaction_notification WHERE to_user_id = #{toUserId} AND unread_count > 0
AND (update_time < #{cursorTime} OR (update_time = #{cursorTime} AND notification_id < #{cursorId}))
ORDER BY update_time DESC, notification_id DESC LIMIT #{limit}

